INSERT INTO `hotel` (`id`, `name`, `description`, `address`, `city`, `province`, `phone`, `star_rating`, `cover_image`, `images`, `facilities`, `check_in_time`, `check_out_time`, `min_price`, `status`, `created_at`, `updated_at`) VALUES
(1, '锦江国际大酒店', '位于市中心繁华地段，交通便利，周边商圈林立。酒店拥有豪华装修，提供一流的住宿体验和贴心服务。设有中西餐厅、健身中心、室内恒温泳池和商务中心。', '中山路188号', '上海', '上海市', '021-88881111', 5, '/images/hotel/hotel1_cover.jpg', '[\"/images/hotel/hotel1_1.jpg\",\"/images/hotel/hotel1_2.jpg\",\"/images/hotel/hotel1_3.jpg\"]', '[\"WiFi\",\"停车场\",\"游泳池\",\"健身房\",\"餐厅\",\"商务中心\",\"洗衣服务\",\"行李寄存\"]', '14:00', '12:00', 588.00, 1, '2025-01-01 00:00:00', '2025-01-01 00:00:00'),
(2, '希尔顿花园酒店', '坐落于城市新区核心位置，毗邻会展中心与高铁站。现代简约风格设计，客房宽敞明亮，配备智能家居系统。酒店设有全日制餐厅和空中花园酒吧。', '新城大道299号', '北京', '北京市', '010-66662222', 5, '/images/hotel/hotel2_cover.jpg', '[\"/images/hotel/hotel2_1.jpg\",\"/images/hotel/hotel2_2.jpg\"]', '[\"WiFi\",\"停车场\",\"健身房\",\"餐厅\",\"会议室\",\"机场接送\",\"SPA\"]', '15:00', '12:00', 698.00, 1, '2025-01-05 00:00:00', '2025-01-05 00:00:00'),
(3, '如家精选酒店', '经济实惠的商旅酒店，干净整洁，设施齐全。紧邻地铁站出口，步行仅需3分钟。提供自助早餐和24小时前台服务，是商务出行的理想选择。', '解放路66号', '广州', '广东省', '020-33334444', 3, '/images/hotel/hotel3_cover.jpg', '[\"/images/hotel/hotel3_1.jpg\"]', '[\"WiFi\",\"停车场\",\"餐厅\",\"洗衣服务\",\"行李寄存\"]', '14:00', '12:00', 268.00, 1, '2025-01-10 00:00:00', '2025-01-10 00:00:00'),
(4, '万豪度假酒店', '坐拥湖光山色的度假胜地，远离城市喧嚣。酒店依山傍水而建，拥有私家花园和湖畔栈道。设有温泉中心、户外无边泳池、儿童乐园和水上运动中心。', '湖滨路1号', '杭州', '浙江省', '0571-55556666', 5, '/images/hotel/hotel4_cover.jpg', '[\"/images/hotel/hotel4_1.jpg\",\"/images/hotel/hotel4_2.jpg\",\"/images/hotel/hotel4_3.jpg\",\"/images/hotel/hotel4_4.jpg\"]', '[\"WiFi\",\"停车场\",\"游泳池\",\"健身房\",\"餐厅\",\"SPA\",\"温泉\",\"儿童乐园\",\"KTV\"]', '14:00', '13:00', 888.00, 1, '2025-01-15 00:00:00', '2025-01-15 00:00:00'),
(5, '汉庭优佳酒店', '全新升级的品质商旅酒店，客房采用零压床垫和高品质棉织品，提供舒适睡眠体验。位于火车站商圈，周边餐饮购物便利。', '火车站南广场路12号', '成都', '四川省', '028-77778888', 3, '/images/hotel/hotel5_cover.jpg', '[\"/images/hotel/hotel5_1.jpg\"]', '[\"WiFi\",\"停车场\",\"自助洗衣\",\"行李寄存\"]', '14:00', '12:00', 228.00, 1, '2025-02-01 00:00:00', '2025-02-01 00:00:00'),
(6, '丽思卡尔顿酒店', '奢华五星级酒店，位于中央商务区黄金地段。酒店融合东方美学与现代奢华，提供管家式个性化服务。设有米其林餐厅、屋顶花园和艺术画廊。', '金融街8号', '深圳', '广东省', '0755-99990000', 5, '/images/hotel/hotel6_cover.jpg', '[\"/images/hotel/hotel6_1.jpg\",\"/images/hotel/hotel6_2.jpg\"]', '[\"WiFi\",\"代客泊车\",\"游泳池\",\"健身房\",\"米其林餐厅\",\"SPA\",\"管家服务\",\"机场接送\"]', '15:00', '12:00', 1288.00, 1, '2025-02-10 00:00:00', '2025-02-10 00:00:00'),
(7, '亚朵轻居酒店', '人文主题酒店，以阅读和摄影为主题，大堂设有免费借阅图书馆。客房设计简约温馨，提供特色茶饮和人文关怀。适合文艺青年和品质旅行者。', '大学城路88号', '南京', '江苏省', '025-11112222', 4, '/images/hotel/hotel7_cover.jpg', '[\"/images/hotel/hotel7_1.jpg\",\"/images/hotel/hotel7_2.jpg\"]', '[\"WiFi\",\"停车场\",\"图书馆\",\"咖啡厅\",\"洗衣服务\",\"行李寄存\"]', '14:00', '12:00', 358.00, 1, '2025-02-20 00:00:00', '2025-02-20 00:00:00'),
(8, '全季酒店', '中高端商务酒店品牌，秉承简约自然的设计理念。客房空间利用合理，床品舒适，淋浴系统出色。早餐种类丰富，性价比极高。', '科技园路55号', '武汉', '湖北省', '027-44445555', 4, '/images/hotel/hotel8_cover.jpg', '[\"/images/hotel/hotel8_1.jpg\"]', '[\"WiFi\",\"停车场\",\"餐厅\",\"健身房\",\"洗衣服务\"]', '14:00', '12:00', 328.00, 1, '2025-03-01 00:00:00', '2025-03-01 00:00:00'),
(9, '维也纳国际酒店', '音乐主题商务酒店，大堂常有轻柔钢琴演奏。客房装饰典雅，隔音效果好。设有中西自助餐厅和私人影院。适合商务接待和家庭入住。', '中华路168号', '长沙', '湖南省', '0731-66667777', 4, '/images/hotel/hotel9_cover.jpg', '[\"/images/hotel/hotel9_1.jpg\",\"/images/hotel/hotel9_2.jpg\"]', '[\"WiFi\",\"停车场\",\"餐厅\",\"KTV\",\"影院\",\"洗衣服务\",\"会议室\"]', '14:00', '12:00', 388.00, 1, '2025-03-10 00:00:00', '2025-03-10 00:00:00'),
(10, '桔子水晶酒店', '设计师精品酒店，每家门店拥有独特的设计主题。客房配备JBL音响、科勒卫浴和金可儿床垫。位于老城区，步行可达多个景点。', '古城街23号', '西安', '陕西省', '029-88889999', 4, '/images/hotel/hotel10_cover.jpg', '[\"/images/hotel/hotel10_1.jpg\"]', '[\"WiFi\",\"餐厅\",\"酒吧\",\"行李寄存\"]', '14:00', '12:00', 418.00, 1, '2025-03-20 00:00:00', '2025-03-20 00:00:00'),
(11, '七天优品酒店', '经济型连锁酒店，简洁实用，价格亲民。房间虽小但五脏俱全，WiFi快速稳定。适合预算有限的短途旅行者和背包客。', '商业步行街9号', '重庆', '重庆市', '023-22223333', 2, '/images/hotel/hotel11_cover.jpg', '[\"/images/hotel/hotel11_1.jpg\"]', '[\"WiFi\",\"行李寄存\"]', '14:00', '12:00', 158.00, 1, '2025-04-01 00:00:00', '2025-04-01 00:00:00'),
(12, '凯悦臻选酒店', '位于滨海度假区的高端酒店，拥有无敌海景房和私人沙滩。设有海鲜自助餐厅、水上运动中心和日落观景台。', '海滨大道1号', '三亚', '海南省', '0898-33334444', 5, '/images/hotel/hotel12_cover.jpg', '[\"/images/hotel/hotel12_1.jpg\",\"/images/hotel/hotel12_2.jpg\",\"/images/hotel/hotel12_3.jpg\"]', '[\"WiFi\",\"停车场\",\"私人沙滩\",\"游泳池\",\"健身房\",\"SPA\",\"水上运动\",\"餐厅\",\"酒吧\"]', '15:00', '11:00', 1088.00, 0, '2025-04-10 00:00:00', '2025-04-10 00:00:00');

