(8, 4, '湖景大床房', '面朝湖泊的豪华大床房，阳台可直接欣赏湖景日出', 888.00, 1088.00, 2, '大床', 40.00, '3-10层', '[\"WiFi\",\"迷你吧\",\"保险箱\",\"浴缸\",\"阳台\",\"吹风机\"]', '[\"/images/room/room8_1.jpg\",\"/images/room/room8_2.jpg\"]', 1, 1, 25, 1, '2025-01-15 00:00:00', '2025-01-15 00:00:00'),
(9, 4, '亲子主题房', '精心布置的亲子房，配备儿童帐篷、玩具和动画主题装饰', 1088.00, 1288.00, 4, '大床+上下铺', 50.00, '3-6层', '[\"WiFi\",\"迷你吧\",\"儿童帐篷\",\"玩具\",\"儿童浴袍\"]', '[\"/images/room/room9_1.jpg\"]', 1, 1, 10, 1, '2025-01-15 00:00:00', '2025-01-15 00:00:00'),
(10, 4, '独栋湖畔别墅', '私密独栋别墅，拥有私人花园、露天浴池和独立车位', 3888.00, 4588.00, 6, '大床+双床', 200.00, '1层', '[\"WiFi\",\"私人花园\",\"露天浴池\",\"厨房\",\"洗衣机\",\"独立车位\"]', '[\"/images/room/room10_1.jpg\",\"/images/room/room10_2.jpg\"]', 1, 1, 3, 1, '2025-01-15 00:00:00', '2025-01-15 00:00:00'),
