-- -----------------------------------------------------------
-- 评价数据
-- -----------------------------------------------------------
INSERT INTO `review` (`id`, `user_id`, `hotel_id`, `order_id`, `room_type_id`, `rating`, `content`, `images`, `status`, `reply`, `reply_at`, `created_at`, `updated_at`) VALUES
(1, 2, 1, 1, 1, 5, '酒店位置非常好，房间干净整洁，服务态度一流！大床很舒服，早餐种类丰富。下次来上海还会选择这里。', NULL, 1, '感谢您的好评，期待您再次光临！', '2025-06-13 10:00:00', '2025-06-12 14:00:00', '2025-06-13 10:00:00'),
(2, 3, 4, 2, 8, 5, '湖景房名不虚传，推开窗就是美丽的湖景。亲子设施也很棒，孩子玩得很开心。温泉体验非常放松，强烈推荐家庭度假！', NULL, 1, '感谢您的认可，我们一直致力于为家庭提供最好的度假体验！', '2025-06-24 09:00:00', '2025-06-23 15:00:00', '2025-06-24 09:00:00'),
(3, 4, 3, 3, 6, 4, '性价比很高的酒店，虽然房间不大但很干净。早餐一般，但价格摆在这里不能要求太多。交通方便是最大的优点。', NULL, 1, '感谢您的评价，我们会持续改善早餐品质！', '2025-07-08 10:00:00', '2025-07-07 16:00:00', '2025-07-08 10:00:00'),
(4, 5, 7, 4, 15, 5, '亚朵的人文气息真的很足，房间里的书籍和茶具让人感觉很温馨。枕头可以选择不同软硬度，睡眠质量很好。', NULL, 1, NULL, NULL, '2025-07-27 18:00:00', '2025-07-27 18:00:00'),
(5, 2, 6, 5, 13, 5, '丽思卡尔顿不愧是顶级酒店，管家服务细致入微，房间的海景令人震撼。虽然价格不菲，但体验绝对值得。', NULL, 1, '感谢您选择丽思卡尔顿，很高兴为您带来美好的回忆！', '2025-08-09 14:00:00', '2025-08-08 20:00:00', '2025-08-09 14:00:00'),
(6, 6, 3, 16, 7, 3, '房间比较小，隔音一般，能听到走廊的声音。不过价格确实便宜，卫生也过关，临时住一晚还是可以的。', NULL, 1, NULL, NULL, '2025-08-17 14:00:00', '2025-08-17 14:00:00'),
(7, 7, 5, 17, 12, 4, '床垫确实舒服，零压感觉不错。房间装修简洁但有设计感，比同价位的快捷酒店好很多。', NULL, 0, NULL, NULL, '2025-08-26 15:00:00', '2025-08-26 15:00:00'),
(8, 2, 10, 18, 20, 4, '设计感很强的酒店，JBL音响音质很好，科勒的卫浴体验也不错。位置在古城区，逛景点很方便。', NULL, 1, '感谢您对我们设计理念的欣赏！', '2025-09-14 11:00:00', '2025-09-13 16:00:00', '2025-09-14 11:00:00'),
(9, 5, 8, 19, 17, 4, '商务出差的好选择，房间安静，WiFi快，办公区域设计合理。早餐品种丰富，推荐给商旅人士。', NULL, 1, NULL, NULL, '2025-10-22 18:00:00', '2025-10-22 18:00:00'),
(10, 3, 7, 20, 16, 5, '几木大床房太惊喜了！原木风格非常治愈，投影仪可以躺在床上看电影，太幸福了。下次还要住这个房型。', NULL, 0, NULL, NULL, '2025-11-17 15:00:00', '2025-11-17 15:00:00'),
(11, 8, 1, 21, 3, 5, '总统套房真的太奢华了！独立客厅宽敞气派，管家服务贴心周到。用来庆祝升职，这个体验终生难忘。', NULL, 2, NULL, NULL, '2025-12-07 20:00:00', '2025-12-07 20:00:00'),
(12, 10, 6, 22, 14, 5, '丽思套房跨年体验太棒了，在顶层看烟花，房间里的一切都是顶级的。管家还准备了惊喜蛋糕，感动！', NULL, 1, '圣诞快乐，新年快乐！感谢您选择与我们一起跨年！', '2025-12-29 10:00:00', '2025-12-28 22:00:00', '2025-12-29 10:00:00'),
(13, 7, 4, 23, 10, 5, '独栋别墅简直是梦想中的度假方式！私人花园很大，露天浴池泡着看星星，全家人都玩得超级开心。', NULL, 1, NULL, NULL, '2026-01-08 20:00:00', '2026-01-08 20:00:00'),
(14, 6, 2, 24, 4, 4, '希尔顿品质还是很有保证的，梦之床确实好睡。位置靠近高铁站，出差很方便。希望前台效率能再快一些。', NULL, 1, '感谢您的反馈，我们已优化前台入住流程！', '2026-01-22 10:00:00', '2026-01-21 15:00:00', '2026-01-22 10:00:00'),
(15, 4, 11, 25, 22, 3, '最基本的住宿需求能满足，干净卫生没问题。但设施确实简陋了些，隔音也一般。适合临时过夜，不适合长住。', NULL, 1, NULL, NULL, '2026-01-27 16:00:00', '2026-01-27 16:00:00');

