INSERT INTO `announcement` (`id`, `title`, `content`, `type`, `status`, `publish_time`, `created_at`, `updated_at`) VALUES
(1, '欢迎使用酒店预订管理系统', '尊敬的用户，欢迎使用我们的酒店预订管理系统！我们致力于为您提供最便捷的酒店预订体验，覆盖全国各大城市的优质酒店资源。如有任何问题，请随时联系客服。', 3, 1, '2025-01-01 08:00:00', '2025-01-01 08:00:00', '2025-01-01 08:00:00'),
(2, '春节特惠活动 - 最高享85折', '春节将至，我们推出了丰富的优惠活动！2026年1月15日至2月28日期间，预订合作酒店可享受最高85折优惠。更有新春红包券等您领取，让您的春节出行更加实惠。', 2, 1, '2026-01-10 10:00:00', '2026-01-10 10:00:00', '2026-01-10 10:00:00'),
(3, '系统升级公告', '为了给您提供更好的服务体验，我们将于2026年2月15日凌晨2:00-6:00进行系统升级维护。届时可能会出现短暂无法访问的情况，请您提前做好预订安排。给您带来的不便，敬请谅解。', 1, 1, '2026-02-01 09:00:00', '2026-02-01 09:00:00', '2026-02-01 09:00:00'),
(4, '情人节浪漫套餐上线', '情人节即将到来，我们精选了多家浪漫酒店推出情人节专属套餐，包含双人晚餐、鲜花布置和SPA体验。数量有限，先到先得！', 2, 1, '2026-02-05 10:00:00', '2026-02-05 10:00:00', '2026-02-05 10:00:00'),
(5, '会员积分制度说明', '为回馈广大用户，我们推出了会员积分制度。每消费1元可获得1积分，积分可兑换优惠券和免费房晚。详情请查看个人中心-积分说明。', 1, 1, '2025-06-01 10:00:00', '2025-06-01 10:00:00', '2025-06-01 10:00:00'),
(6, '暑期亲子游推荐（已结束）', '暑期亲子游攻略已上线，精选全国各地最适合带孩子入住的酒店和度假村，更有专属亲子优惠券等您领取。', 2, 2, '2025-07-01 09:00:00', '2025-07-01 09:00:00', '2025-10-01 00:00:00'),
(7, '用户隐私保护声明（草稿）', '我们高度重视您的个人信息保护，严格遵守相关法律法规...(内容草稿待完善)', 3, 0, NULL, '2026-02-06 14:00:00', '2026-02-06 14:00:00');

